//! Death #2 — Amplituhedron scattering-amplitude kernel (math layer).
//!
//! Companion to `amplituhedron.rs`, which owns the *runtime cache* (LRU
//! prefix-hash → KV slab). This file owns the *math*: Plücker
//! coordinates, k-subset enumeration, vertex counting, and the
//! amplituhedron scattering amplitude. The two modules are deliberately
//! split:
//!
//!   * `amplituhedron.rs` — opaque post-prefill volume cache, layout
//!     agnostic, no math content. Already in production.
//!   * `scattering_amplitude.rs` (this file) — the Lean-formalised
//!     kernel for Death #2. The Grassmannian compiler will eventually
//!     consume `plucker_vector` to validate that a candidate k-plane
//!     lives in Gr⁺(k, d) before the cache is allowed to capture.
//!
//! This module is **additive** — nothing in the live forward pass calls
//! it yet. The next milestone wires `is_positive` into the integration
//! step as a positivity guard before `AmplituhedronCache::capture`.
//!
//! ## Lean ↔ Rust contract
//!
//! Every public item here mirrors a definition in
//! `open-source/gnosis-math/Gnosis/Amplituhedron{Grassmannian,Vertices,
//! Witnesses,Falsifiability,CoverageSweep}.lean`. The `#[cfg(test)]`
//! block at the bottom of this file pins down the exact Lean oracle
//! values — if Lean and Rust disagree, the tests fail. The Lean side
//! is authoritative; do not weaken assertions to make tests pass.
//!
//! Key correspondences (Lean → Rust):
//!
//!   * `kSubsets`              → [`k_subsets`]
//!   * `det` / `detFueled`     → [`det`]
//!   * `submatrix`             → [`submatrix`]
//!   * `KPlane k d`            → [`KPlane`]
//!   * `pluckerCoord`          → [`KPlane::plucker_coord`]
//!   * `pluckerVector`         → [`plucker_vector`]
//!   * `isPositiveBool`        → [`is_positive`]
//!   * `scatteringAmplitude`   → [`scattering_amplitude`]
//!   * `vertexCount`           → [`vertex_count`]
//!
//! Coords are `i64`. Lean uses `Int` (arbitrary precision); for the
//! oracle witnesses (small Vandermonde, coordinate planes, k ≤ 3,
//! d ≤ 12) `i64` is comfortably wide. If the runtime ever feeds in
//! large hidden-state submatrices, this kernel must be revisited (and
//! the Lean side ported to a bounded-precision variant or kept on
//! `Int` with explicit overflow guards on the Rust boundary).

#![allow(dead_code)]

// ════════════════════════════════════════════════════════════════════
// k-SUBSET ENUMERATION (kSubsets in Lean)
// ════════════════════════════════════════════════════════════════════

/// Ordered k-subsets of `[0..d)` in reverse-lex order, matching the
/// Lean recursion exactly:
///
/// ```text
/// kSubsets 0     _     = [[]]
/// kSubsets (k+1) 0     = []
/// kSubsets (k+1) (d+1) = (kSubsets k d).map(s => s ++ [d])
///                          ++ kSubsets (k+1) d
/// ```
///
/// Concretely, `k_subsets(2, 4)` yields
/// `[[2,3], [1,3], [0,3], [1,2], [0,2], [0,1]]` — the recursive arm
/// places subsets containing the maximal element `d-1` first.
pub fn k_subsets(k: usize, d: usize) -> Vec<Vec<usize>> {
    if k == 0 {
        return vec![vec![]];
    }
    if d == 0 {
        return vec![];
    }
    let d_minus_1 = d - 1;
    let mut head: Vec<Vec<usize>> = k_subsets(k - 1, d_minus_1)
        .into_iter()
        .map(|mut s| {
            s.push(d_minus_1);
            s
        })
        .collect();
    head.extend(k_subsets(k, d_minus_1));
    head
}

// ════════════════════════════════════════════════════════════════════
// DETERMINANT (Laplace cofactor expansion along first row)
// ════════════════════════════════════════════════════════════════════

/// Laplace cofactor expansion along the first row, matching Lean's
/// `detFueled (rows.length) rows`:
///
/// * Empty matrix → 1 (Lean convention; matches `det_nil`).
/// * Otherwise, `Σ_{j} sign(j) * row0[j] * det(minor_j)` where
///   `sign(j) = +1` for even j and `-1` for odd j, and `minor_j` is the
///   submatrix with row 0 and column j removed.
///
/// Indexing into a row past its length yields 0, mirroring Lean's
/// `row.getD j 0`. The function does not check that the matrix is
/// square; callers feeding non-square input get the cofactor sum
/// expansion of whatever shape they passed (in practice all callers go
/// through [`KPlane::plucker_coord`], which selects a k×k minor).
pub fn det(matrix: &[Vec<i64>]) -> i64 {
    if matrix.is_empty() {
        return 1;
    }
    let row0 = &matrix[0];
    let rest = &matrix[1..];
    let mut acc: i64 = 0;
    for j in 0..row0.len() {
        let sign: i64 = if j % 2 == 0 { 1 } else { -1 };
        let entry: i64 = *row0.get(j).unwrap_or(&0);
        let minor: Vec<Vec<i64>> = rest
            .iter()
            .map(|r| {
                let mut out = Vec::with_capacity(r.len().saturating_sub(1));
                for (col_idx, v) in r.iter().enumerate() {
                    if col_idx != j {
                        out.push(*v);
                    }
                }
                out
            })
            .collect();
        acc += sign * entry * det(&minor);
    }
    acc
}

// ════════════════════════════════════════════════════════════════════
// SUBMATRIX SELECTION (submatrix in Lean)
// ════════════════════════════════════════════════════════════════════

/// Select columns `cols` from each row, mirroring Lean's
/// `submatrix : List (List Int) → List Nat → List (List Int)` which is
/// `rows.map (fun row => cols.map (fun j => row.getD j 0))`. An
/// out-of-range column index yields 0.
pub fn submatrix(rows: &[Vec<i64>], cols: &[usize]) -> Vec<Vec<i64>> {
    rows.iter()
        .map(|row| cols.iter().map(|&j| *row.get(j).unwrap_or(&0)).collect())
        .collect()
}

// ════════════════════════════════════════════════════════════════════
// k-PLANE IN d-SPACE  (KPlane k d in Lean)
// ════════════════════════════════════════════════════════════════════

/// A k-plane in d-space, represented as k row vectors of length d over
/// `i64`. Mirrors Lean `structure KPlane (k d : Nat)` whose fields
/// (`rows`, `rank_witness`, `width_witness`) carry the same shape
/// invariants. In Rust the witnesses are runtime-checked at
/// construction by [`KPlane::new`]; once built, downstream code can
/// rely on `rows.len() == k` and `rows[i].len() == d` for all `i`.
#[derive(Debug, Clone)]
pub struct KPlane {
    pub k: usize,
    pub d: usize,
    pub rows: Vec<Vec<i64>>,
}

/// Construction error for [`KPlane::new`]. Distinct variants so the
/// Grassmannian compiler can route bad layer outputs to the right
/// telemetry bucket.
#[derive(Debug, PartialEq, Eq)]
pub enum KPlaneError {
    /// `rows.len() != k`. Carries `(expected_k, actual_rows)`.
    RankMismatch(usize, usize),
    /// Some row has length ≠ `d`. Carries `(row_index, expected_d, actual_len)`.
    WidthMismatch(usize, usize, usize),
}

impl KPlane {
    /// Construct a `KPlane`, validating both shape invariants.
    /// Returns `Err` instead of panicking so the runtime can degrade
    /// gracefully if a malformed candidate plane arrives over the wire.
    pub fn new(k: usize, d: usize, rows: Vec<Vec<i64>>) -> Result<Self, KPlaneError> {
        if rows.len() != k {
            return Err(KPlaneError::RankMismatch(k, rows.len()));
        }
        for (i, row) in rows.iter().enumerate() {
            if row.len() != d {
                return Err(KPlaneError::WidthMismatch(i, d, row.len()));
            }
        }
        Ok(Self { k, d, rows })
    }

    /// Plücker coordinate at column subset `cols`: determinant of the
    /// k×k submatrix on those columns. Mirrors Lean
    /// `pluckerCoord (p : KPlane k d) (cols : List Nat) : Int`.
    pub fn plucker_coord(&self, cols: &[usize]) -> i64 {
        det(&submatrix(&self.rows, cols))
    }
}

/// The full vector of Plücker coordinates: one entry per ordered
/// k-subset of `[0..d)`, in the same order as [`k_subsets`]. Mirrors
/// Lean `pluckerVector (p : KPlane k d) : List Int`.
pub fn plucker_vector(plane: &KPlane) -> Vec<i64> {
    k_subsets(plane.k, plane.d)
        .iter()
        .map(|cols| plane.plucker_coord(cols))
        .collect()
}

/// Decidable positivity check: every Plücker coordinate is strictly
/// `> 0`. Mirrors Lean
/// `isPositiveBool (p : KPlane k d) : Bool := (pluckerVector p).all (fun c => decide (c > 0))`.
///
/// `true` ⇒ the plane lives in the open positive Grassmannian
/// Gr⁺(k, d). `false` ⇒ either a strictly negative coord or at least
/// one zero coord (boundary).
pub fn is_positive(plane: &KPlane) -> bool {
    plucker_vector(plane).iter().all(|&c| c > 0)
}

// ════════════════════════════════════════════════════════════════════
// SCATTERING AMPLITUDE
// ════════════════════════════════════════════════════════════════════

/// Scattering amplitude on a k-plane, given a dual covector aligned to
/// the Plücker vector. Mirrors the Lean amplitude evaluation
///
/// ```text
/// (pluckerVector p).zip dual |>.foldl (fun acc p => acc + p.1 * p.2) 0
/// ```
///
/// If `dual.len() < plucker_vector(plane).len()` the trailing Plücker
/// coords are ignored (matching `List.zip` truncation semantics in
/// Lean). If `dual` is longer, the trailing duals are likewise ignored.
pub fn scattering_amplitude(plane: &KPlane, dual: &[i64]) -> i64 {
    plucker_vector(plane)
        .iter()
        .zip(dual.iter())
        .fold(0_i64, |acc, (p, d)| acc + p * d)
}

// ════════════════════════════════════════════════════════════════════
// VERTEX COUNT  (vertexCount in Lean)
// ════════════════════════════════════════════════════════════════════

/// Vertex count of Gr⁺(k, d): `(kSubsets k d).length`, equivalently
/// `C(d, k)`. Mirrors Lean `vertexCount (k d : Nat) : Nat`. We compute
/// via `k_subsets` rather than a closed-form binomial so this function
/// is, by construction, the exact same number Lean's
/// `native_decide` reduces.
pub fn vertex_count(k: usize, d: usize) -> usize {
    k_subsets(k, d).len()
}

// ════════════════════════════════════════════════════════════════════
// LEAN ORACLE TESTS — MUST MATCH gnosis-math EXACTLY
// ════════════════════════════════════════════════════════════════════

#[cfg(test)]
mod tests {
    use super::*;

    /// Helper: build the Vandermonde 2×4 witness matching Lean
    /// `vandermonde_2_4 : KPlane 2 4` in `AmplituhedronWitnesses.lean`.
    fn vandermonde_2_4() -> KPlane {
        KPlane::new(2, 4, vec![vec![1, 2, 4, 8], vec![1, 3, 9, 27]])
            .expect("vandermonde witness has correct shape")
    }

    /// Helper: build the coordinate plane spanned by [0, 1] in
    /// 3-space — Lean's `coordPlane_2_3_01`. Rows are unit vectors
    /// e_0 and e_1.
    fn coord_plane_2_3_01() -> KPlane {
        KPlane::new(2, 3, vec![vec![1, 0, 0], vec![0, 1, 0]])
            .expect("coordinate plane has correct shape")
    }

    // ── ORACLE 1: kSubsets reverse-lex order ────────────────────────

    #[test]
    fn k_subsets_2_4_reverse_lex_order() {
        // Lean: kSubsets 2 4 puts subsets containing d-1 first.
        let expected: Vec<Vec<usize>> = vec![
            vec![2, 3],
            vec![1, 3],
            vec![0, 3],
            vec![1, 2],
            vec![0, 2],
            vec![0, 1],
        ];
        assert_eq!(k_subsets(2, 4), expected);
    }

    #[test]
    fn k_subsets_zero_returns_singleton_empty() {
        // Lean: kSubsets 0 _ = [[]]
        let empty: Vec<Vec<usize>> = vec![vec![]];
        assert_eq!(k_subsets(0, 0), empty);
        assert_eq!(k_subsets(0, 7), empty);
    }

    #[test]
    fn k_subsets_k_gt_d_is_empty() {
        // Lean: kSubsets (k+1) 0 = []  (and by induction k > d gives [])
        let empty: Vec<Vec<usize>> = Vec::new();
        assert_eq!(k_subsets(3, 2), empty);
    }

    #[test]
    fn k_subsets_1_3_matches_lean_witness() {
        // Lean theorem kSubsets_1_3: kSubsets 1 3 = [[2], [1], [0]]
        let expected: Vec<Vec<usize>> = vec![vec![2], vec![1], vec![0]];
        assert_eq!(k_subsets(1, 3), expected);
    }

    // ── ORACLE 2 / 8: vertexCount values across the coverage sweep ──

    #[test]
    fn vertex_count_2_4_equals_6() {
        // Lean theorem vertexCount_2_4: vertexCount 2 4 = 6
        assert_eq!(vertex_count(2, 4), 6);
    }

    #[test]
    fn coverage_sweep_vertex_counts_match_lean() {
        // Lean Gnosis.AmplituhedronCoverageSweep:
        //   (2,4) → 6, (2,6) → 15, (2,8) → 28,
        //   (3,6) → 20, (3,9) → 84, (3,12) → 220.
        assert_eq!(vertex_count(2, 4), 6, "(2,4) coverage point");
        assert_eq!(vertex_count(2, 6), 15, "(2,6) coverage point");
        assert_eq!(vertex_count(2, 8), 28, "(2,8) coverage point");
        assert_eq!(vertex_count(3, 6), 20, "(3,6) coverage point");
        assert_eq!(vertex_count(3, 9), 84, "(3,9) coverage point");
        assert_eq!(vertex_count(3, 12), 220, "(3,12) coverage point");
    }

    // ── ORACLE 3 / 4: Vandermonde Plücker vector ───────────────────

    #[test]
    fn vandermonde_2_4_plucker_vector_matches_lean_oracle() {
        // Lean theorem vandermonde_2_4_plucker_vector:
        //   pluckerVector vandermonde_2_4 = [36, 30, 19, 6, 5, 1].
        // Each entry is the 2×2 minor on the corresponding kSubset:
        //   [2,3] → 4*27 - 8*9 = 36
        //   [1,3] → 2*27 - 8*3 = 30
        //   [0,3] → 1*27 - 8*1 = 19
        //   [1,2] → 2*9  - 4*3 =  6
        //   [0,2] → 1*9  - 4*1 =  5
        //   [0,1] → 1*3  - 2*1 =  1
        let plane = vandermonde_2_4();
        assert_eq!(plucker_vector(&plane), vec![36, 30, 19, 6, 5, 1]);
    }

    // ── ORACLE 5: Vandermonde is in Gr⁺(2,4) ───────────────────────

    #[test]
    fn vandermonde_2_4_is_positive() {
        // Lean theorem vandermonde_2_4_isPositive:
        //   isPositiveBool vandermonde_2_4 = true.
        assert!(is_positive(&vandermonde_2_4()));
    }

    // ── ORACLE 6: coordinate plane lives on the Gr⁺ boundary ──────

    #[test]
    fn coord_plane_2_3_01_is_boundary() {
        // Lean theorem coordPlane_2_3_01_not_in_positive:
        //   isPositiveBool coordPlane_2_3_01 = false.
        // Plücker vector is [det e0e1 cols, ...] with two zeros:
        //   [1,2] → 0,  [0,2] → 0,  [0,1] → 1.
        let plane = coord_plane_2_3_01();
        let pv = plucker_vector(&plane);
        assert_eq!(pv, vec![0, 0, 1], "coord plane boundary Plücker vector");
        assert!(!is_positive(&plane), "coord plane is on Gr⁺ boundary");
    }

    // ── ORACLE 7: scattering amplitude inner product ──────────────

    #[test]
    fn vandermonde_amplitude_equals_97() {
        // Lean theorem vandermonde_2_4_amplitude:
        //   ⟨[36,30,19,6,5,1], [1,1,1,1,1,1]⟩ = 97.
        let plane = vandermonde_2_4();
        let dual = vec![1_i64, 1, 1, 1, 1, 1];
        assert_eq!(scattering_amplitude(&plane, &dual), 97);
    }

    // ── DETERMINANT BASE CASES (Lean det_*_concrete witnesses) ────

    #[test]
    fn det_empty_matrix_is_one() {
        // Lean theorem det_nil: det [] = 1.
        let m: Vec<Vec<i64>> = vec![];
        assert_eq!(det(&m), 1);
    }

    #[test]
    fn det_one_by_one_matches_lean() {
        // Lean theorem det_one_concrete: det [[7]] = 7.
        assert_eq!(det(&[vec![7]]), 7);
    }

    #[test]
    fn det_two_by_two_matches_lean() {
        // Lean theorem det_two_concrete: det [[2,3],[1,4]] = 5.
        assert_eq!(det(&[vec![2, 3], vec![1, 4]]), 5);
    }

    #[test]
    fn det_three_by_three_identity() {
        // Lean theorem det_three_identity: det I_3 = 1.
        assert_eq!(det(&[vec![1, 0, 0], vec![0, 1, 0], vec![0, 0, 1]]), 1);
    }

    // ── SUBMATRIX SELECTION (mirrors Lean submatrix) ──────────────

    #[test]
    fn submatrix_selects_columns_in_order() {
        let rows = vec![vec![10, 20, 30, 40], vec![50, 60, 70, 80]];
        // cols [0, 2] → keep first and third entry of each row.
        assert_eq!(submatrix(&rows, &[0, 2]), vec![vec![10, 30], vec![50, 70]]);
    }

    #[test]
    fn submatrix_out_of_range_yields_zero() {
        // Mirror Lean's `row.getD j 0` semantics.
        let rows = vec![vec![1, 2]];
        assert_eq!(submatrix(&rows, &[0, 5]), vec![vec![1, 0]]);
    }

    // ── KPlane construction validation ────────────────────────────

    #[test]
    fn kplane_rejects_wrong_rank() {
        let r = KPlane::new(2, 3, vec![vec![1, 0, 0]]);
        // Use `matches!` because `KPlane` deliberately omits `PartialEq`
        // (the live runtime never compares planes for equality — Plücker
        // vectors are the witness of identity, not row layout).
        assert!(matches!(r, Err(KPlaneError::RankMismatch(2, 1))));
    }

    #[test]
    fn kplane_rejects_wrong_width() {
        let r = KPlane::new(2, 3, vec![vec![1, 0, 0], vec![1, 0]]);
        assert!(matches!(r, Err(KPlaneError::WidthMismatch(1, 3, 2))));
    }
}
